import asyncio
import json
import math
from dataclasses import dataclass, asdict
from typing import Dict, Set
from datetime import datetime

@dataclass
class Player:
    id: str
    x: float
    y: float
    z: float
    health: int
    team: str
    alive: bool

class BattleRoyaleServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.clients: Dict[str, asyncio.StreamWriter] = {}
        self.visibility_range = 100.0
        self.server_tick_rate = 0.05
        
    def calculate_distance(self, p1: Player, p2: Player) -> float:
        return math.sqrt((p1.x - p2.x)**2 + (p1.y - p2.y)**2 + (p1.z - p2.z)**2)
    
    def is_visible(self, observer: Player, target: Player) -> bool:
        if not observer.alive or not target.alive:
            return False
        
        distance = self.calculate_distance(observer, target)
        if distance > self.visibility_range:
            return False
        
        # Server-side line of sight check (simplified)
        # In production, use proper raycasting against game world geometry
        return True
    
    def get_visible_players(self, player_id: str) -> list:
        if player_id not in self.players:
            return []
        
        observer = self.players[player_id]
        visible_players = []
        
        for pid, player in self.players.items():
            if pid == player_id:
                continue
            
            # Server authoritative visibility check
            if self.is_visible(observer, player):
                visible_players.append({
                    'id': player.id,
                    'x': player.x,
                    'y': player.y,
                    'z': player.z,
                    'health': player.health,
                    'team': player.team,
                    'alive': player.alive
                })
        
        return visible_players
    
    async def handle_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        addr = writer.get_extra_info('peername')
        player_id = None
        
        try:
            # Authentication and player setup
            data = await reader.read(1024)
            message = json.loads(data.decode())
            
            if message['type'] == 'join':
                player_id = message['player_id']
                self.players[player_id] = Player(
                    id=player_id,
                    x=message.get('x', 0),
                    y=message.get('y', 0),
                    z=message.get('z', 0),
                    health=100,
                    team=message.get('team', 'solo'),
                    alive=True
                )
                self.clients[player_id] = writer
                
                response = {
                    'type': 'joined',
                    'player_id': player_id,
                    'status': 'success'
                }
                writer.write(json.dumps(response).encode() + b'\n')
                await writer.drain()
            
            # Main game loop for this client
            while True:
                data = await asyncio.wait_for(reader.read(4096), timeout=30.0)
                if not data:
                    break
                
                message = json.loads(data.decode())
                
                if message['type'] == 'update_position':
                    if player_id in self.players:
                        # Server validates and updates position
                        player = self.players[player_id]
                        player.x = message['x']
                        player.y = message['y']
                        player.z = message['z']
                
                elif message['type'] == 'request_state':
                    # Send only visible players to this client
                    visible_players = self.get_visible_players(player_id)
                    
                    response = {
                        'type': 'game_state',
                        'timestamp': datetime.utcnow().isoformat(),
                        'your_position': asdict(self.players[player_id]) if player_id in self.players else None,
                        'visible_players': visible_players
                    }
                    
                    writer.write(json.dumps(response).encode() + b'\n')
                    await writer.drain()
                
        except asyncio.TimeoutError:
            print(f"Client {addr} timed out")
        except Exception as e:
            print(f"Error handling client {addr}: {e}")
        finally:
            if player_id:
                if player_id in self.players:
                    del self.players[player_id]
                if player_id in self.clients:
                    del self.clients[player_id]
            writer.close()
            await writer.wait_closed()
    
    async def broadcast_game_state(self):
        """Broadcast personalized game state to each client based on their visibility"""
        while True:
            await asyncio.sleep(self.server_tick_rate)
            
            for player_id, writer in list(self.clients.items()):
                try:
                    if player_id not in self.players:
                        continue
                    
                    # Each client receives only what they can see
                    visible_players = self.get_visible_players(player_id)
                    
                    state = {
                        'type': 'state_update',
                        'timestamp': datetime.utcnow().isoformat(),
                        'your_position': asdict(self.players[player_id]),
                        'visible_players': visible_players,
                        'alive_count': sum(1 for p in self.players.values() if p.alive)
                    }
                    
                    writer.write(json.dumps(state).encode() + b'\n')
                    await writer.drain()
                    
                except Exception as e:
                    print(f"Error broadcasting to {player_id}: {e}")
    
    async def start_server(self, host='0.0.0.0', port=8888):
        server = await asyncio.start_server(self.handle_client, host, port)
        addr = server.sockets[0].getsockname()
        print(f'Battle Royale Server running on {addr}')
        
        # Start broadcast task
        broadcast_task = asyncio.create_task(self.broadcast_game_state())
        
        async with server:
            await server.serve_forever()

